script:
frappe.ui.form.on("Hostel Application", {
    refresh(frm) {
        if (frm.is_new()) return;

        if (frm.doc.status === "Submitted") {
            frm.add_custom_button("Approve", function() {
                frappe.confirm(
                    `Approve hostel application for ${frm.doc.student}?`,
                    () => {
                        frm.set_value("status", "Approved");
                        frm.save();
                    }
                );
            }).addClass("btn-primary");

            frm.add_custom_button("Reject", function() {
                frappe.prompt(
                    { fieldname: "reason", label: "Rejection Reason", fieldtype: "Small Text", reqd: 1 },
                    (values) => {
                        frm.set_value("status", "Rejected");
                        frm.save();
                    },
                    "Reject Application"
                );
            });
        }

        if (frm.doc.status === "Approved") {
            frm.dashboard.set_headline_alert(
                "✓ Approved — Hostel Admission created automatically.", "green"
            );
        }
    }
});
